import{_ as e,o as n,c as o,ag as a}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"SMTP Connections","description":"","frontmatter":{},"headers":[],"relativePath":"features/connections.md","filePath":"features/connections.md"}'),i={name:"features/connections.md"};function s(r,t,d,c,l,h){return n(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="smtp-connections" tabindex="-1">SMTP Connections <a class="header-anchor" href="#smtp-connections" aria-label="Permalink to &quot;SMTP Connections&quot;">​</a></h1><p>SendGrail manages email delivery through SMTP connections. You can configure multiple connections for different providers and switch between them as needed.</p><h2 id="creating-a-connection" tabindex="-1">Creating a Connection <a class="header-anchor" href="#creating-a-connection" aria-label="Permalink to &quot;Creating a Connection&quot;">​</a></h2><p>To create a new connection, navigate to <strong>Connections</strong> and click <strong>Add Connection</strong>.</p><h3 id="provider-selection" tabindex="-1">Provider Selection <a class="header-anchor" href="#provider-selection" aria-label="Permalink to &quot;Provider Selection&quot;">​</a></h3><p>Start by selecting your email provider from the preset list. Provider presets automatically fill and lock provider-specific fields such as host, port, and encryption method, reducing configuration errors.</p><p>If your provider is not listed, select <strong>Other / Custom SMTP</strong> to manually configure all fields.</p><h3 id="connection-fields" tabindex="-1">Connection Fields <a class="header-anchor" href="#connection-fields" aria-label="Permalink to &quot;Connection Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Host</strong></td><td>SMTP server hostname (e.g., <code>smtp.gmail.com</code>)</td></tr><tr><td><strong>Port</strong></td><td>SMTP port (typically 587 for TLS, 465 for SSL, 25 for none)</td></tr><tr><td><strong>Encryption</strong></td><td><code>TLS</code>, <code>SSL</code>, or <code>None</code></td></tr><tr><td><strong>Authentication</strong></td><td>Whether the server requires authentication</td></tr><tr><td><strong>Username</strong></td><td>SMTP username (often the email address)</td></tr><tr><td><strong>Password</strong></td><td>SMTP password or app-specific password</td></tr><tr><td><strong>From Email</strong></td><td>The sender email address</td></tr><tr><td><strong>From Name</strong></td><td>The sender display name</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>When using Gmail, you must generate an <strong>App Password</strong> from your Google Account security settings. Your regular Gmail password will not work with SMTP.</p></div><h2 id="editing-a-connection" tabindex="-1">Editing a Connection <a class="header-anchor" href="#editing-a-connection" aria-label="Permalink to &quot;Editing a Connection&quot;">​</a></h2><p>When editing an existing connection, the password field displays dots to indicate a stored value. If you leave the password field unchanged, the existing password is preserved. Only enter a new value if you intend to change it.</p><h2 id="enabling-and-disabling-connections" tabindex="-1">Enabling and Disabling Connections <a class="header-anchor" href="#enabling-and-disabling-connections" aria-label="Permalink to &quot;Enabling and Disabling Connections&quot;">​</a></h2><p>Each connection can be individually enabled or disabled. A disabled connection will not be used for sending emails, even if referenced by a routing rule.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The default connection cannot be disabled. To disable it, you must first set a different connection as the default.</p></div><h2 id="setting-the-default-connection" tabindex="-1">Setting the Default Connection <a class="header-anchor" href="#setting-the-default-connection" aria-label="Permalink to &quot;Setting the Default Connection&quot;">​</a></h2><p>One connection must always be designated as the <strong>default</strong>. The default connection is used for all outgoing emails unless a routing rule directs the email to a different connection.</p><p>When you set a connection as the default, any previously designated default connection is automatically deactivated from that role.</p><h2 id="testing-connections" tabindex="-1">Testing Connections <a class="header-anchor" href="#testing-connections" aria-label="Permalink to &quot;Testing Connections&quot;">​</a></h2><p>SendGrail provides a raw SMTP socket test to verify that a connection can communicate with the mail server. The test performs the following steps:</p><ol><li>Opens a socket connection to the SMTP host and port</li><li>Sends the <code>EHLO</code> command to identify the client</li><li>Initiates <code>TLS</code> encryption if configured</li><li>Performs <code>AUTH</code> with the provided credentials</li></ol><p>This test validates the connection at the transport level without sending an actual email. Use the <a href="/features/test-simulate">Test Email</a> feature to send a real message.</p><h2 id="connection-health-table" tabindex="-1">Connection Health Table <a class="header-anchor" href="#connection-health-table" aria-label="Permalink to &quot;Connection Health Table&quot;">​</a></h2><p>The connections list displays health information for each configured connection:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Status</strong></td><td>Current connection state (active, inactive, error)</td></tr><tr><td><strong>Last Tested</strong></td><td>Timestamp of the most recent connection test</td></tr></tbody></table><h2 id="per-connection-statistics" tabindex="-1">Per-Connection Statistics <a class="header-anchor" href="#per-connection-statistics" aria-label="Permalink to &quot;Per-Connection Statistics&quot;">​</a></h2><p>Each connection tracks its own delivery metrics:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Description</th></tr></thead><tbody><tr><td><strong>Sent Today</strong></td><td>Number of emails successfully sent in the current day</td></tr><tr><td><strong>Total Sent</strong></td><td>Lifetime count of emails sent through this connection</td></tr><tr><td><strong>Fail Rate</strong></td><td>Percentage of failed deliveries relative to total attempts</td></tr></tbody></table><p>These statistics help you monitor the reliability of each provider and identify connections that may need attention.</p><h2 id="password-encryption" tabindex="-1">Password Encryption <a class="header-anchor" href="#password-encryption" aria-label="Permalink to &quot;Password Encryption&quot;">​</a></h2><p>All SMTP passwords are encrypted at rest using <strong>AES-256-CBC</strong> encryption.</p><p>By default, SendGrail uses the WordPress <code>AUTH_KEY</code> constant as the encryption key. For enhanced security, you can define a dedicated encryption key by adding the following to your <code>wp-config.php</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">define</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;SENDGRAIL_ENCRYPTION_KEY&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;your-secure-random-string-here&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>If you change or lose the encryption key, all stored SMTP passwords become unreadable. You will need to re-enter the password for every connection.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The <code>SENDGRAIL_ENCRYPTION_KEY</code> takes precedence over <code>AUTH_KEY</code> when defined. Use a strong, random string of at least 32 characters.</p></div>',35)])])}const g=e(i,[["render",s]]);export{u as __pageData,g as default};
